css:
/*作者：@kuku（小红书同名）  */

/*⚠️ 此css美化禁二传二改·禁商用倒卖*/


/*手机美化适配二改自@多云熊老师*/

/* === 字体=== */
@font-face {
  font-family: "MiaoMiao";  
  src: url("https://files.catbox.moe/hch67y.tt") format("truetype");
  font-display: swap;       
}

body, button, input, textarea {
  font-family: "MiaoMiao", "Microsoft YaHei", sans-serif !important;
}




/*ui背景图🍉🍉*/
.drawer-content {
    background-image: url('https://files.catbox.moe/ssp1fj.jpg');
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
}




/* 头像位置 */
div[is_user] .mesAvatarWrapper { 
    position: absolute;
    top: -3px !important; /* char头像上下位置🍉 */
    left: 50% !important;/* user和char头像的左右位置🍉 */
    transform: translateX(-50%);
    z-index: 5;
    margin: 0 !important;
}


div[is_user="true"] .mesAvatarWrapper {
    top: -3px !important; /* user头像的上下位置🍉 */
}


.avatar img {
    width: 40px !important;  
    height: 40px !important;
    min-width: unset !important;
    min-height: unset !important;
    box-shadow: none !important; 
    transition: all 0.3s ease; 
}

/* 头像尺寸调整 - 覆盖原有样式 */
.avatar img {
    width: 55px !important;  /* 宽🍉 */
    height: 55px !important; /* 高🍉 */
    object-fit: cover !important; 
    border-radius: 500% !important; 
    box-shadow: 0 4px 12px rgba(255,255,255,0.5) !important; 
}

/* ---边框--- */
.avatar img {
  border: 0px solid #FFF1C6; 
  box-shadow: 0 0 0 2px rgba(255, 255, 255, 1) !important; 
  box-sizing: border-box; 
}

/* 禁止交互 */
.avatar, 
.avatar img,
.mesAvatarWrapper {
  pointer-events: none !important; 
  cursor: default !important; 
  user-select: none !important; 
}

#right-nav-panel .avatar,
#right-nav-panel .avatar img,
#character_popup .avatar {
  pointer-events: auto !important;  
  cursor: pointer !important;      
  user-select: auto !important;    
}


/* 调整对话框基础尺寸 */
.mes {
    --bubble-width: 90%;  
    --vertical-spacing: 2rem; 

    width: var(--bubble-width) !important;
    min-height: var(--bubble-min-height);
    margin: var(--vertical-spacing) auto !important; 
    padding: 1rem -0.2rem !important; 
    left: 6px;
}

/* 框长度 */
.mes_text {
    padding: 35px 1px 35px 1px !important; /* 上 右 下 左 */
}

.mes_block {
    position: relative;
    z-index: 999 !important; 
    isolation: isolate; 
}




/* 气泡 */
.mes[is_user="true"] {
    background: linear-gradient(
        to bottom, 
        rgba(255, 255, 255, 1) 60%,  
        rgba(255, 255, 255, 1) 100%
    ) !important;
    border: px solid #ceb7c6 !important; 
    box-shadow: 0 2px 4px rgba(170,153,153,0.2) !important;
    border-radius: 5px !important;
}

/* AI */
.mes[is_user="false"] {
    background: linear-gradient(
        to bottom,
        rgba(255, 255, 255, 1) 60%,  
        rgba(255, 255, 255, 1) 100%
    ) !important;
    border: 0px solid #ceb7c6 !important; 
    box-shadow: 0 4px 5px rgba(193,209,234,0.5) !important;
    border-radius: 5px !important;
}

.mes_block {
    position: relative;
    z-index: 2;
}

/* 头像框*/
.avatar::after {
    content: "";
    position: absolute;
    top: -11px;
    left: -6px;
    width: calc(80% + 25px);
    height: calc(96% + 25px);
    background-image: url("https://files.catbox.moe/7j1qzf.gif");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 5 !important;
    pointer-events: none;

}

.avatar::before {
    content: "";
    position: absolute;
    top: -126px;
    left: -160px;
    width: calc(80% + 320px);
    height: calc(96% + 310px);
    background-image: url("https://files.catbox.moe/3rup4o.png");
    background-size: contain;
    background-repeat: no-repeat;
    z-index: 5 !important;
    pointer-events: none;

}

/* 心 */
.fa-circle-stop::before {
  content: "" !important; 
  display: inline-block;
  width: 1em !important;   
  height: 1em !important;
  background: url("https://files.catbox.moe/xs5adf.gif") center/contain no-repeat; 
  vertical-align: middle !important;
  animation: spin 2s linear infinite; 
  transition: 0.3s ease;
}

q {
  text-decoration: underline dotted rgba(0, 0, 0, 0.3);
  text-underline-offset: 4px;
  font-style: normal;
}


.mes::before, .mes::after {
    content: "";
    position: absolute;
    top: 0;
    height: 100%;
    width: 20px; 
    background-image: url('https://files.catbox.moe/d18pbn.png');
    background-repeat: repeat-y;
    background-size: contain;
    z-index: 1;
    opacity: 0.9; 
    pointer-events: none; 
}

.mes::before {
    left: -15px; 
    background-position: right center;
}

.mes::after {
    right: -13px; 
    background-position: left center;
    transform: scaleX(-1); 
}

/* 消息ID */
.mesIDDisplay {
    position: absolute !important;
    top: 60px !important;
    left: 18px !important;
    display: inline-block !important;
    font-size: 0.7em !important;
    font-family: "MiaoMiao";
    z-index: 888 !important;
    opacity: 0.6;
}

/* 时间戳 */
.mes_timer {
    position: absolute !important;
    top: 60px !important;
    left: 62px !important;  
    font-size: 0.7em !important;
    color: var(--text-color-sec) !important;
    display: flex !important;
    gap: 4px;
    z-index: 888 !important;
    opacity: 0.6;
}

/* 词符数 */
.tokenCounterDisplay {
    position: absolute !important;
    top: 60px !important;
    left: 110px !important;  
    display: flex !important;
    font-size: 0.7em !important;
    z-index: 888 !important;
    opacity: 0.6;
}

#chat .ch_name {
  position: relative;
  display: flex;
  color: #9DA9B7 !important;
  padding: 1px 0; 
  top: 30px !important;
    left: 10px !important;
  width: 90%; /* 用户名宽度 */
  max-width: 280px; /* 最大宽度限制 */
}

#sheld {
    background: linear-gradient(rgba(0, 0, 0, 0), rgba(0, 0, 0, 0)), 
                url('https://files.catbox.moe/hsj0o5.jpg') !important;
    background-size: cover !important;
    background-position: center !important;
    background-attachment: fixed !important;
    background-repeat: no-repeat !important;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
  --border-thickness: 2px; /* 边框高度控制变量 */
  --border-radius: 12px; 

  background-color: #F2F8FF !important;
  position: relative;
  border-radius: var(--border-radius) !important;
  overflow: visible !important; 
  z-index: 1;
  box-shadow: 
    inset 0 0 0 var(--border-thickness) #fff,
    inset 0 0 0 calc(var(--border-thickness) + 2px) #B3A0A0,

    0 2px 2px rgba(227, 240, 255, 0.3);
  transition: all 0.3s ease;
}

#completion_prompt_manager .completion_prompt_manager_footer {
    padding: 0px;
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span,
#completion_prompt_manager .completion_prompt_manager_header_advanced span {
    filter: drop-shadow(0px 0px 2px var(--SmartThemeChatTintColor));
}

#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: var(--customThemeColor-purple);
}

.text_pole:not(.objective-task) {
  background-color: var(--ui-color-sec);
  border: none;
}

blockquote,
.quote-style,
[class*="quote"] {
    background-color: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 0 !important;
    margin: 0.8em 0 !important;
}

blockquote::before,
blockquote::after {
    content: "" !important;
}

/* 添加在全局样式中 */
#top-bar {

   z-index: 1000; 
}

#top-bar::after {
    content: "";
    position: fixed;
    top: var(--topBar-height, -70px); 
    left: 0px;
    width: 102%;
    height: 120px;
    background: url('https://files.catbox.moe/79o7hy.png') center/cover no-repeat;
    z-index: 999; 
    pointer-events: none; 
    filter: opacity(0.) drop-shadow(0 2px 4px rgba(0,0,0,0.0));
}

#main-content {
    margin-top: 150px; 
}



#top-bar::before {
    content: "";
    position: absolute;
    bottom: -75px;
    left: 93%;
    transform: translateX(-50%);
    width: 75%;
    height: 75px;
    background: url("https://files.catbox.moe/xu74xc.png") center/contain no-repeat;
    mix-blend-mode: luminosity;
    opacity: 1;

    animation: pendulumSwing 9s ease-in-out infinite;
    transform-origin: top center; 
}


@keyframes pendulumSwing {
    0% {
        transform: translateX(-50%) rotate(-15deg); 
    }
    25% {
        transform: translateX(-50%) rotate(15deg); 
    }
    50% {
        transform: translateX(-50%) rotate(-15deg); 
    }
    75% {
        transform: translateX(-50%) rotate(10deg); 
    }
    100% {
        transform: translateX(-50%) rotate(-15deg); 
    }
}

/* 滑块图案 */
input[type="range"]::-webkit-slider-thumb {
    width: 30px;
    height: 45px; 
    background: url('https://files.catbox.moe/3ebrvf.png') no-repeat center center; 
    background-size: contain; 
    border: none;
    border-radius: 0; 
    box-shadow: none;
    transition: width 0.2s, height 0.2s;
    z-index: 2;
}

input[type="range"] {
    background: #FFF8E6 !important;
    box-shadow: none !important; 
    border: 1px solid #ceb7c6 !important;
    height: 4px; 
}

.avatar,
.avatar::before,
.avatar::after {
    z-index: auto !important; 
}

/* 代码块 */
code, .hljs {
  position: relative;
  background: linear-gradient(
    20deg,
    rgba(255,250,236,0.8) 10%,
    rgba(236,248,255,0.8) 40%
  ) !important;
  border-radius: 4px !important;
  border: 1px solid #ECF7FF !important;
  box-shadow: 
    2px 1px 1px rgba(136,169,197,0.1), 
    inset -1px -1px 2px rgba(0,0,0,0.01), 
    inset 1px 1px 1px rgba(136,169,197,0.1); 
  border: 1px solid rgba(200,200,255,0.) !important;
  transition: all 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94);
   color: #9D8573;
}

/* ===== 外部装饰图标 ===== */
pre {
  position: relative; 
  margin-bottom: 2em !important; 
  overflow: visible !important; 
}

pre::after {
  content: "";
  position: absolute;
  bottom: -12px;  
  right: -5px;
  width: 40px;    
  height: 40px;
  background-image: url("https://files.catbox.moe/53sldm.gif");
  background-size: contain;

  transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
  z-index: 1; 
}


/* 下拉框 */
select {
    --jelly-color: #E6F7FF;   
    --shadow-color: #F4E2CC; 
    background: 
        linear-gradient(145deg, 
            rgba(242,248,255,1) 10%, 
            rgba(242,248,255,1) 90%) !important;
    border: px solid rgba(45,45,45,0.) !important;
    border-radius: 5px !important;
    box-shadow:
        0 2px 2px -4px rgba(69,69,69,0.5),
        inset 0 1px 1px rgba(255,255,255,0.1),
        inset 0 -1px 0.5px rgba(69,69,69,0.1) !important;
    padding: px 36px 10px 16px !important;
    color: #63676C !important;
}

select option {
    text-align: center !important;
    text-align-last: center !important; 
}

/* 自定义勾选框配色 */
input[type="checkbox"] {
    --checkbox-bg: #F4E2CC;  
    --checkbox-accent: #DEC4A5; 

    background-color: var(--checkbox-bg) !important;
    box-shadow: 0 0 0 px var(--checkbox-accent) !important;
    transition: all 0.2s ease;
    border-radius: 15px !important;
}

/* 对勾符号 */
input[type="checkbox"]::before {
    box-shadow: inset 1em 1em var(--checkbox-bg) !important;
    filter: contrast(0.1);
}

/* 勾选图标 */
input[type="checkbox"]:checked::after {
    content: "";
    position: absolute;
    left: 50%;
    top: 50%;
    transform: translate(-50%, -50%);
    font-size: 12px;
    line-height: 1;
    color: #454545;
    text-shadow: 0 2px 4px rgba(255,107,107,0.2);
}

/* 标题样式 */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#user-settings-block h4,
.standoutHeader {
  background-size: 110%;
  overflow: visible !important;
  background-image: url("https://files.catbox.moe/82x4vx.jpeg");
  border: 1px dashed #CEC0AD !important;
  box-shadow: 
    inset 0 0 0 2px #fff,
    0 2px 2px rgba(0, 0, 0, 0.08),
    inset 0 0 8px rgba(243, 246, 255, 1) !important;
  border-radius: 5px;
  transition: all 0.2s cubic-bezier(0.34, 1.56, 0.64, 1);
  position: relative;
  overflow: hidden;
  padding: 5px 26px !important;
}

/* 添加右侧装饰图 */
.inline-drawer-header::after,
#extensions_settings .inline-drawer-toggle.inline-drawer-header::after,
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header::after,
#user-settings-block h4::after,
.standoutHeader::after {
  content: "";
  position: absolute;
  top: 40%;
  right: 110px; 
  transform: translateY(-50%) rotate(0deg); 
  width: 130px; 
  height: 130px; 
  background-image: url("https://files.catbox.moe/bosgoc.png"); 
  background-size: contain;
  background-repeat: no-repeat;
  background-position: center;
  z-index: 10; /* 确保在标题框上方 */
  filter: drop-shadow(2px 3px 5px rgba(0,0,0,0.)); /* 添加投影 */
  opacity: 1; /* 适当透明度 */
  transition: all 0.3s ease;
}

/* 极简滚动条 */
::-webkit-scrollbar {
    width: 4px !important; 
    height: 5px !important; 
}

::-webkit-scrollbar-track {
    background: transparent !important; /* 完全透明轨道 */
}

::-webkit-scrollbar-thumb {
    background: linear-gradient(to bottom, 
        #FFFEEC 0%, 
        #FFFEEC 5%, 
        #FFFEEC 51%, 
        #FFFEEC 100%) !important;
    border-radius: 2px !important;
    border: none !important;
    transition: all 0.3s ease !important;
}

/* 输入框 */
input[type="text"],
input[type="number"],
input[type="switch"],
input:not([type]),
textarea:not([type="search"]) {
    background-color: #FFFFFF !important; 
    border-radius: 2px !important;
    border: 1px dashed #B4ACAC !important;
}

/* 上移输入框容器 */
#form_sheld {
  margin: 0 auto -10px auto !important; 
  transform: translateY(-20px); 
}

/* 调整输入框内边距 */
#send_form {
  padding: 0px 1px !important; 
  border-radius: 15px !important;
  width: 93.3% !important; 
    max-width: 1200px;
    min-height: 1px !important;
    box-shadow: 
    0 0 0 2.2px #836d7C,    
    0 0 0 4px #FFFFFF,    
    0 0 0 5px #D3E1F6;    
}

#form_sheld::before {
    content: "";
    position: absolute;
    top: -66px; 
    left: 50%;
    transform: translateX(-50%);
    width: 385px; 
    height: 150px; 
    background-image: url("https://files.catbox.moe/c301kp.png"); 
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    z-index: 1; 
    pointer-events: none; 
    transition: all 0.3s ease; 
}

/* 思维链 */
.mes_reasoning_header {
    background: #FFF !important;
    border: 1.5px solid #E7F2FF !important;
    border-radius: 5px !important;
    box-shadow: 0 2px 4px rgba(193,209,234,0.3) !important;
    color: #C8D2DE !important;
    font-weight: 500;
    padding: 1px 15px !important;
    left: -1% !important;
    top: 35px !important;
}


/* 角色管理头像 */
#right-nav-panel .character_select .avatar {
    --avatar-base-size: 50px !important; 
    width: var(--avatar-base-size) !important;
    height: var(--avatar-base-size) !important;
    transform: scale(1) !important; 
    margin: -2px auto !important; 
    border: 1px solid #CAD1D9;
}


#right-nav-panel .character_select .avatar img {
    width: 100% !important;
    height: 100% !important;
    object-fit: cover;
    border-radius: 50px !important;
    box-shadow: 0 4px 5px rgba(213,213,213,0.9) !important;
}

/* 禁用收藏标记 */
#right-nav-panel .character_select.is_fav .avatar,
#persona-management-button .character_select.is_fav .avatar {
    outline: none !important;
    box-shadow: none !important;
}

#right-nav-panel .character_select.is_fav .ch_name,
#persona-management-button .character_select.is_fav .ch_name {
    color: inherit !important;
}


/* 移除特定界面头像装饰 */
#character_popup .avatar::before, 
#character_popup .avatar::after,
#user-settings-block .avatar::before, 
#user-settings-block .avatar::after,
#right-nav-panel .avatar::before, 
#right-nav-panel .avatar::after {
    display: none !important;
    background-image: none !important;
    animation: none !important;
}

/* 删掉 */
#persona-management-button .avatar::before,
#persona-management-button .avatar::after {
    content: none !important;
    display: none !important;
}


::-webkit-scrollbar-thumb:vertical {
    background-color: #FFEDF5;
    box-shadow: none;    
}

/* neo-range-input 背景美化 */
.neo-range-input {
    position: relative;
    background: linear-gradient(
            to right,
            rgba(255,255,255,0.2) 0%,
            rgba(255,255,255,0.1) 100%
        ),

    background-blend-mode: soft-light, multiply;
    box-shadow: inset 0 2px 8px rgba(0,0,0,0.03) !important;
}

@keyframes messageAppear {
  0% {
    opacity: 0;
    transform: translateY(40px) scale(0.95);
  }
  100% {
    opacity: 1;
    transform: translateY(0) scale(1);
  }
}

.mes {
  animation: messageAppear 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards;
  opacity: 0; 
  transform-origin: center bottom;
}




/* 去除阴影 */
.mes_button,
.mes_edit_buttons,
#completion_prompt_manager
  #completion_prompt_manager_list
  li.completion_prompt_manager_prompt
  span
  span
  span {
  filter: none !important;
}

input:disabled, 
select:disabled, 
textarea:disabled {
  background: rgba(237, 229, 216, 0.6) !important;
  color: #9E7C6E !important;
  border-style: dashed !important;
}

.drawer-icon::before,
#leftNavDrawerIcon::before,
#rightNavDrawerIcon::before {
    content: '';
    display: block;
    width: 40px;
    height: 40px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    margin-right: px;
    margin-left: -8px;
}
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 12px;
}

/* 调整图标容器样式 */
.drawer-icon {
    display: flex;
    align-items: center;
    justify-content: flex-start;
    padding-left: 6px;
}

/* 强制非悬停 */
.drawer-icon,
.fa-bars,
#extensionsMenuButton,
.fa-paper-plane {
  opacity: 1 !important;
  transition: opacity 0.2s ease !important;
}

/* 左侧导航图标 */
#leftNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/tmoo6c.png');
}

/* 系统设置图标 */
#sys-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/gdl8x4.png');
}

/* 高级格式图标 */
#advanced-formatting-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/tmoo6c.png');
}

/* 世界信息图标 */
#WI-SP-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/gdl8x4.png');
}

/* 用户设置图标 */
#user-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/tmoo6c.png');
}

/* Logo图标 */
#logo_block .drawer-icon::before {
    background-image: url('https://files.catbox.moe/gdl8x4.png');
}

/* 扩展设置图标 */
#extensions-settings-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/tmoo6c.png');
}

/* 记忆表格 */
#table_drawer_icon::before {
    background-image: url('https://files.catbox.moe/gdl8x4.png');
}

/* 角色管理图标 */
#persona-management-button .drawer-icon::before {
    background-image: url('https://files.catbox.moe/tmoo6c.png');
}

/* 右侧导航图标 */
#rightNavDrawerIcon::before {
    background-image: url('https://files.catbox.moe/gdl8x4.png');
}

/* 特殊按钮样式 */
/* 菜单按钮 */
.fa-bars {
  background: url('https://files.catbox.moe/5mpru7.png') center/contain no-repeat !important;
  width: 34px !important;
  height: 35px !important;

}

/* 扩展按钮 */
#extensionsMenuButton {
  background: url('https://files.catbox.moe/zzypzr.png') center/contain no-repeat !important;
  width: 35px !important;
  height: 35px !important;
